const defaults={accounts:[{id:'LT-25K-7481',firm:'Lucid Trading',size:25000,stage:'Funded',rule:'Lucid Trading (25K)'},{id:'FN-50K-5623',firm:'Funded Next',size:50000,stage:'Funded',rule:'Funded Next (50K)'},{id:'TF-50K-3098',firm:'Tradeify',size:50000,stage:'Evaluation',rule:'Tradeify (50K)'}],rules:[{name:'Lucid Trading (25K)',size:25000,dd:1000,drawdown:'Static',target:1250,daily:500,benchmark:100,days:5,buffer:1000,maxWithdrawal:1000,min:250},{name:'Funded Next (50K)',size:50000,dd:2000,drawdown:'Trailing',target:3000,daily:1000,benchmark:250,days:1,buffer:2100,maxWithdrawal:1250,min:250},{name:'Tradeify (50K)',size:50000,dd:2000,drawdown:'Trailing',target:3000,daily:1000,benchmark:200,days:1,buffer:2100,maxWithdrawal:6000,min:250}],balances:[{date:'2026-07-13',id:'LT-25K-7481',balance:25000},{date:'2026-07-14',id:'LT-25K-7481',balance:25011.75},{date:'2026-07-15',id:'LT-25K-7481',balance:24474},{date:'2026-07-16',id:'LT-25K-7481',balance:24260.65},{date:'2026-07-17',id:'LT-25K-7481',balance:24444},{date:'2026-07-17',id:'FN-50K-5623',balance:49620.50},{date:'2026-07-17',id:'TF-50K-3098',balance:51280}],withdrawals:[]};
let data=JSON.parse(localStorage.getItem('proppulse-data')||'null')||defaults;data.rules.forEach((r,i)=>{r.maxWithdrawal??=[1000,1250,6000][i]||1000;r.buffer??=r.dd;r.days??=0;r.benchmark??=0;r.drawdown='Trailing';r.firm??=(data.accounts.find(a=>a.rule===r.name)?.firm||r.name.replace(/\s*\([^)]*\)/,'').trim());r.accountType??=(data.accounts.find(a=>a.rule===r.name)?.stage||'Standard')});data.accounts.forEach(a=>{a.accountType??=(data.rules.find(r=>r.name===a.rule)?.accountType||'Standard');a.friendlyName??=a.id});let pending=[],selectedAccountId=data.accounts[0]?.id,calendarDate=new Date(2026,6,1);const $=s=>document.querySelector(s),$$=s=>[...document.querySelectorAll(s)];const fmt=n=>new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:2}).format(n||0);const dateFmt=d=>new Date(d+'T12:00:00').toLocaleDateString('en-GB',{day:'2-digit',month:'short',year:'numeric'});const databaseApi=location.protocol==='file:'?'http://127.0.0.1:4174/api/state':'/api/state';const save=()=>{localStorage.setItem('proppulse-data',JSON.stringify(data));fetch(databaseApi,{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify({data,users:JSON.parse(localStorage.getItem('proppulse-users')||'[]')})}).catch(()=>{})};
function metrics(a){const rule=data.rules.find(r=>r.name===a.rule)||{};const entries=data.balances.filter(b=>b.id===a.id).sort((x,y)=>x.date.localeCompare(y.date));const balance=entries.at(-1)?.balance??a.size;const peak=Math.max(a.size,...entries.map(x=>x.balance));const trailingLoss=Math.max(0,peak-balance);const fundedFloorLocked=a.stage==='Funded'&&peak>=a.size+(rule.dd||0);const floor=fundedFloorLocked?a.size:peak-(rule.dd||0);const ddLeft=Math.max(0,fundedFloorLocked?balance-a.size:(rule.dd||0)-trailingLoss),profit=balance-a.size;const lastW=data.withdrawals.filter(w=>w.id===a.id).sort((x,y)=>y.date.localeCompare(x.date))[0];const cycle=entries.filter(e=>!lastW||e.date>lastW.date);let prior=a.size;const hits=entries.reduce((n,e)=>{const pnl=e.balance-prior;prior=e.balance;return n+((!lastW||e.date>lastW.date)&&pnl>=(rule.benchmark||0)&&pnl>0?1:0)},0);const bufferRemaining=Math.max(0,(rule.buffer||0)-profit);const benchmarkRemaining=Math.max(0,(rule.days||0)-hits);const withdrawable=a.stage==='Funded'&&!(bufferRemaining>0||benchmarkRemaining>0)?Math.min(Math.max(0,profit),rule.maxWithdrawal||0):0;let status;if(a.stage==='Evaluation')status=profit>=rule.target?'Passed':ddLeft<=(rule.dd||0)*.25?'Low DD':'In Progress';else status=bufferRemaining>0?'Buffer Not Met':benchmarkRemaining>0?`Benchmark Pending (${benchmarkRemaining} Days)`:withdrawable>=(rule.maxWithdrawal||0)?'Max Reached':'Eligible';return{rule,entries,balance,peak,profit,floor,ddLeft,trailingLoss,bufferRemaining,benchmarkRemaining,withdrawable,status,hits,cycle,fundedFloorLocked};}
function statusClass(s){return /Passed|Eligible|standing|Reached/.test(s)?'ok':/Low|Pending|Buffer|risk/.test(s)?'risk':'neutral'}
function renderDashboard(){const states=data.accounts.map(a=>({a,m:metrics(a)}));const live=states.reduce((s,x)=>s+x.m.balance,0),profit=states.reduce((s,x)=>s+x.m.profit,0),atRisk=states.filter(x=>x.m.ddLeft<(x.m.rule.dd||0)*.35).length;$('#metricStrip').innerHTML=`<div class="metric"><span>Total live balance</span><strong>${fmt(live)}</strong><small>Across ${states.length} accounts</small></div><div class="metric"><span>Total open profit</span><strong>${fmt(profit)}</strong><small>From account starting balances</small></div><div class="metric warning"><span>Accounts at risk</span><strong>${atRisk}</strong><small>${atRisk?'Review before trading':'All accounts healthy'}</small></div><div class="metric"><span>Latest balance date</span><strong>${data.balances.length?dateFmt([...data.balances].sort((a,b)=>b.date.localeCompare(a.date))[0].date):'—'}</strong><small>End-of-day records</small></div>`;$('#dashboardRows').innerHTML=states.map(({a,m})=>`<tr class="open-account" data-id="${a.id}"><td><div class="account-name"><span class="initial">${a.firm.slice(0,2).toUpperCase()}</span><span>${a.firm}<small>${a.id}</small></span></div></td><td class="money">${fmt(m.balance)}</td><td class="money ${a.stage==='Funded'&&m.bufferRemaining?'danger':'positive'}">${a.stage==='Funded'?fmt(m.bufferRemaining):fmt(Math.max(0,m.rule.target-m.profit))}</td><td class="money">${fmt(m.ddLeft)}</td><td>${a.stage==='Funded'?m.benchmarkRemaining+' days':'—'}</td><td><span class="pill ${statusClass(m.status)}">${m.status}</span></td></tr>`).join('');$$('.open-account').forEach(r=>r.onclick=()=>openAccount(r.dataset.id));const danger=[...states].sort((x,y)=>x.m.ddLeft-y.m.ddLeft);$('#riskList').innerHTML=danger.slice(0,3).map(({a,m})=>{const pct=Math.min(100,(m.ddLeft/(m.rule.dd||1))*100);return `<div class="risk-item"><div class="risk-top"><span>${a.firm}</span><strong>${fmt(m.ddLeft)} left</strong></div><div class="progress"><span style="width:${pct}%"></span></div></div>`}).join('');renderChart();}
function renderChart(){const byDate={};data.balances.forEach(b=>(byDate[b.date]??=0,byDate[b.date]+=b.balance));const vals=Object.values(byDate).slice(-7);if(!vals.length)return;const min=Math.min(...vals),max=Math.max(...vals),range=max-min||1,pts=vals.map((v,i)=>`${(i/(Math.max(vals.length-1,1))*760+20).toFixed(1)},${(150-((v-min)/range)*110).toFixed(1)}`).join(' ');$('.line').setAttribute('d',`M ${pts.replace(' ',' L ')}`);$('.area').setAttribute('d',`M20,170 L ${pts.replace(/ /g,' L ')} L780,170 Z`);$('#chartValue').textContent=fmt(vals.at(-1));}
function renderBalances(){const rows=[...data.balances].sort((a,b)=>b.date.localeCompare(a.date)).slice(0,12);$('#historyRows').innerHTML=rows.length?rows.map(b=>{const prev=data.balances.filter(x=>x.id===b.id&&x.date<b.date).sort((x,y)=>y.date.localeCompare(x.date))[0],pnl=prev?b.balance-prev.balance:null;return `<tr><td>${dateFmt(b.date)}</td><td>${b.id}</td><td class="money">${fmt(b.balance)}</td><td class="${pnl>=0?'positive':'danger'}">${pnl===null?'—':fmt(pnl)}</td></tr>`}).join(''):'<tr class="empty"><td colspan="4">No balance history yet.</td></tr>';$('#manualAccount').innerHTML=data.accounts.map(a=>`<option value="${a.id}">${a.id} — ${a.firm}</option>`).join('');}
function renderAccounts(){$('#accountRows').innerHTML=data.accounts.map(a=>{const m=metrics(a);return `<tr><td class="money">${a.id}</td><td>${a.firm}</td><td>${fmt(a.size)}</td><td><span class="pill ${a.stage==='Funded'?'ok':'neutral'}">${a.stage}</span></td><td>${fmt(m.balance)}</td><td><button class="text-btn open-account-btn" data-id="${a.id}">Open →</button> <button class="text-btn delete-account" data-id="${a.id}">Remove</button></td></tr>`}).join('');$$('.open-account-btn').forEach(b=>b.onclick=()=>openAccount(b.dataset.id));$$('.delete-account').forEach(b=>b.onclick=()=>{data.accounts=data.accounts.filter(a=>a.id!==b.dataset.id);data.balances=data.balances.filter(x=>x.id!==b.dataset.id);save();renderAll();toast('Account removed');});}
