function renderPreview(){const valid=pending.filter(p=>p.account&&Number.isFinite(p.balance)),issues=pending.length-valid.length;$('#readyCount').textContent=`${valid.length} account${valid.length===1?'':'s'}`;$('#issueCount').textContent=`${issues} row${issues===1?'':'s'}`;$('#confirmImport').disabled=!valid.length;$('#previewCaption').textContent=pending.length?`${valid.length} matched · ${issues} need attention`:'Choose a file to preview its account matches.';$('#previewRows').innerHTML=pending.length?pending.map(p=>`<tr><td>${p.id||'—'}</td><td>${p.account?.firm||'—'}</td><td class="money">${Number.isFinite(p.balance)?fmt(p.balance):'—'}</td><td><span class="pill ${p.account&&Number.isFinite(p.balance)?'ok':'risk'}">${p.account&&Number.isFinite(p.balance)?'✓ Matched':'! '+(p.error||'Account not found')}</span></td></tr>`).join(''):'<tr class="empty"><td colspan="4">No balances ready to import.</td></tr>';}
