function renderAccountDetail(){const a=data.accounts.find(x=>x.id===selectedAccountId);if(!a)return;const m=metrics(a),r=m.rule,evalStage=a.stage==='Evaluation';$('#detailStage').textContent=`${a.stage.toUpperCase()} ACCOUNT`;$('#detailTitle').textContent=a.firm;$('#detailSubtitle').textContent=`${a.id} · ${fmt(a.size)} account`;$('#detailStatus').textContent=m.status;$('#detailStatus').className=`pill ${statusClass(m.status)}`;const cards=evalStage?[['Remaining profit',fmt(Math.max(0,r.target-m.profit)),r.target?Math.min(100,Math.max(0,m.profit/r.target*100)):0],['DD left',fmt(m.ddLeft),r.dd?m.ddLeft/r.dd*100:0],['Status',m.status,null]]:[['Buffer remaining',fmt(m.bufferRemaining),r.buffer?100-m.bufferRemaining/r.buffer*100:100],['DD left',fmt(m.ddLeft),r.dd?m.ddLeft/r.dd*100:0],['Withdrawable',fmt(m.withdrawable),r.maxWithdrawal?m.withdrawable/r.maxWithdrawal*100:0],['Benchmark remaining',`${m.benchmarkRemaining} days`,r.days?100-m.benchmarkRemaining/r.days*100:100],['Status',m.status,null]];$('#detailMetrics').innerHTML=cards.map(([l,v,p])=>`<article class="panel detail-card"><span>${l}</span><strong>${v}</strong>${p!==null?`<div class="progress"><span style="width:${Math.min(100,Math.max(0,p))}%"></span></div>`:''}</article>`).join('');const target=evalStage?a.size+r.target:a.size+r.buffer;const range=Math.max(target-m.floor,1),point=Math.max(0,Math.min(100,(m.balance-m.floor)/range*100));$('#journeyFloor').textContent=`${fmt(m.floor)} floor`;$('#journeyTarget').textContent=evalStage?`${fmt(target)} target`:`${fmt(target)} buffer met`;$('#journeyPoint').style.left=`calc(${point}% - 7px)`;$('#journeyDd').textContent=fmt(m.ddLeft);$('#journeyBalance').textContent=fmt(m.balance);$('#journeyRemaining').textContent=evalStage?fmt(Math.max(0,r.target-m.profit)):fmt(m.withdrawable);$('#journeyRemainingLabel').textContent=evalStage?'profit remaining':'withdrawable';renderCalendar(a,m);}
function renderCalendar(a,m){const y=calendarDate.getFullYear(),mo=calendarDate.getMonth();$('#calendarMonth').textContent=calendarDate.toLocaleDateString('en-US',{month:'long',year:'numeric'});const first=new Date(y,mo,1).getDay(),days=new Date(y,mo+1,0).getDate(),map={};let prior=a.size;m.entries.forEach(e=>{const pnl=e.balance-prior;prior=e.balance;map[e.date]=pnl});let html='';for(let i=0;i<first;i++)html+='<div class="calendar-cell blank"></div>';for(let d=1;d<=days;d++){const iso=`${y}-${String(mo+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`,pnl=map[iso],kind=pnl>0?'gain':pnl<0?'loss':'';html+=`<div class="calendar-cell ${kind}"><strong>${d}</strong>${pnl!==undefined?`<span>${pnl>0?'+':''}${fmt(pnl)}</span>`:''}</div>`}$('#calendarGrid').innerHTML=html;}
