function ensureAdmin(){const users=localUsers();if(!users.some(u=>u.username==='guru_admin')){users.push({name:'Guru',username:'guru_admin',password:'PropPulse@2026',role:'admin'});saveUsers(users)}}
function isAdmin(){return sessionUser?.role==='admin'}
function renderRules(){const admin=isAdmin();$('#newRuleBtn').classList.toggle('admin-only',!admin);$('#ruleCards').innerHTML=data.rules.map((r,i)=>`<article class="panel rule-card"><div class="rule-card-head"><div><h2>${r.firm||r.name}</h2><p>${r.accountType||'Standard'} · ${fmt(r.size)} · ${r.drawdown} drawdown</p></div><span class="pill ${r.drawdown==='Static'?'ok':'neutral'}">${r.drawdown}</span></div><div class="rule-values"><div><span>Account size</span><strong>${fmt(r.size)}</strong></div><div><span>Max drawdown</span><strong>${fmt(r.dd)}</strong></div><div><span>Profit target</span><strong>${fmt(r.target)}</strong></div><div><span>Daily loss limit</span><strong>${fmt(r.daily)}</strong></div><div><span>Benchmark amount</span><strong>${fmt(r.benchmark)}</strong></div><div><span>Benchmark days</span><strong>${r.days}</strong></div><div><span>Safety buffer</span><strong>${fmt(r.buffer)}</strong></div><div><span>Max withdrawal</span><strong>${fmt(r.maxWithdrawal)}</strong></div></div>${admin?`<div class="rule-actions"><button class="text-btn rule-edit" data-index="${i}">Edit</button><button class="text-btn rule-delete danger" data-index="${i}">Delete</button></div>`:''}</article>`).join('');$$('.rule-edit').forEach(b=>b.onclick=()=>adminRuleEditor(+b.dataset.index));$$('.rule-delete').forEach(b=>b.onclick=()=>{if(confirm('Delete this rule set?')){data.rules.splice(+b.dataset.index,1);save();renderAll();toast('Rule set deleted')}})}
function adminRuleEditor(index){if(!isAdmin())return;const r=data.rules[index],d=$('#formDialog'),f=$('#dialogFields');$('#dialogTitle').textContent='Edit rule set';const inp=(label,id,value,type='text')=>`<label class="input-label">${label}<input id="${id}" type="${type}" value="${value??0}" required /></label>`;f.innerHTML=`<div class="form-grid">${inp('Prop firm name','editFirm',r.firm||'')}${inp('Account type','editType',r.accountType||'')}${inp('Account size','editSize',r.size,'number')}${inp('Max drawdown','editDd',r.dd,'number')}<label class="input-label">Drawdown type<select id="editDrawdown"><option ${r.drawdown==='Static'?'selected':''}>Static</option><option ${r.drawdown==='Trailing'?'selected':''}>Trailing</option></select></label>${inp('Profit target','editTarget',r.target,'number')}${inp('Daily loss limit','editDaily',r.daily,'number')}${inp('Buffer required','editBuffer',r.buffer,'number')}${inp('Benchmark amount','editBenchmark',r.benchmark,'number')}${inp('Benchmark days','editDays',r.days,'number')}${inp('Max withdrawal','editMax',r.maxWithdrawal,'number')}</div>`;$('#dialogSave').onclick=e=>{e.preventDefault();const firm=$('#editFirm').value.trim(),type=$('#editType').value.trim(),size=+$('#editSize').value;Object.assign(r,{firm,accountType:type,size,name:`${firm} — ${type} (${size/1000}K)`,dd:+$('#editDd').value,drawdown:$('#editDrawdown').value,target:+$('#editTarget').value,daily:+$('#editDaily').value,buffer:+$('#editBuffer').value,benchmark:+$('#editBenchmark').value,days:+$('#editDays').value,maxWithdrawal:+$('#editMax').value});data.accounts.filter(a=>a.rule===r.name||a.firm===firm&&a.accountType===type&&a.size===size).forEach(a=>{a.rule=r.name;a.firm=firm;a.accountType=type;a.size=size});save();d.close();renderAll();toast('Rule set updated')};d.showModal()}
function renderProfile(){if(!sessionUser)return;$('#profileInitial').textContent=sessionUser.name.slice(0,1).toUpperCase();$('#profileName').textContent=sessionUser.name;$('#profileUsername').textContent=`@${sessionUser.username}`;$('#profileRole').textContent=isAdmin()?'Administrator':'Member';$('#profileRole').className=`pill ${isAdmin()?'ok':'neutral'}`;$('#adminNote').classList.toggle('hidden',!isAdmin())}
function setSession(user){sessionUser=user;localStorage.setItem('proppulse-session',JSON.stringify(user));document.body.classList.toggle('is-admin',isAdmin());$('#authShell').classList.add('hidden');renderAll();renderProfile()}
function showAuth(){sessionUser=null;localStorage.removeItem('proppulse-session');document.body.classList.remove('is-admin');$('#authShell').classList.remove('hidden')}
function activateAuth(mode){$$('.auth-tab').forEach(b=>b.classList.toggle('active',b.dataset.authMode===mode));$('.auth-name').classList.toggle('hidden',mode!=='signup');$('#authTitle').textContent=mode==='signup'?'Create your account':mode==='admin'?'Administrator sign in':'Welcome back';$('#authText').textContent=mode==='signup'?'Use a name, username, and password. No email needed.':mode==='admin'?'Use your administrator username and password.':'Sign in to your trading desk.';$('#authSubmit').textContent=mode==='signup'?'Create account':'Sign in';$('#authForm').dataset.mode=mode;$('#authError').textContent=''}
ensureAdmin();sessionUser=JSON.parse(localStorage.getItem('proppulse-session')||'null');if(sessionUser)setSession(sessionUser);else showAuth();activateAuth('login');$$('.auth-tab').forEach(b=>b.onclick=()=>activateAuth(b.dataset.authMode));$('#authForm').onsubmit=e=>{e.preventDefault();const mode=$('#authForm').dataset.mode,username=$('#authUsername').value.trim(),password=$('#authPassword').value,name=$('#authName').value.trim(),users=localUsers(),error=$('#authError');if(mode==='signup'){if(!name){error.textContent='Enter your name.';return}if(users.some(u=>u.username.toLowerCase()===username.toLowerCase())){error.textContent='This username is already in use.';return}const user={name,username,password,role:'member'};users.push(user);saveUsers(users);setSession(user);return}const user=users.find(u=>u.username===username&&u.password===password);if(!user||mode==='admin'&&user.role!=='admin'){error.textContent='Invalid username or password.';return}setSession(user)};$('#logoutBtn').onclick=showAuth;$('#changePasswordBtn').onclick=()=>{const password=prompt('Enter a new password (at least 6 characters):');if(!password)return;if(password.length<6){toast('Use at least 6 characters');return}const users=localUsers(),user=users.find(u=>u.username===sessionUser.username);user.password=password;saveUsers(users);sessionUser=user;localStorage.setItem('proppulse-session',JSON.stringify(user));toast('Password updated')};$('#newRuleBtn').onclick=()=>{if(isAdmin())structuredDialog('rule');else toast('Only the administrator can manage rule sets')};

function structuredDialog(type){const d=$('#formDialog'),fields=$('#dialogFields'),saveButton=$('#dialogSave');const input=(label,id,inputType='text',extra='')=>`<label class="input-label">${label}<input id="${id}" type="${inputType}" ${extra} required /></label>`;if(type==='account'){const firms=[...new Set(data.rules.map(r=>r.firm))];$('#dialogTitle').textContent='Add account';fields.innerHTML=`<div class="form-grid">${input('Account ID','newAccountId')}<label class="input-label">1. Prop firm<select id="newFirm">${firms.map(f=>`<option value="${f}">${f}</option>`).join('')}</select></label><label class="input-label">2. Account type<select id="newType"></select></label><label class="input-label">3. Account size<select id="newSize"></select></label><label class="input-label">Account stage<select id="newStage"><option>Funded</option><option>Evaluation</option></select></label><label class="input-label full">4. Rules (selected automatically)<input id="newRuleDisplay" readonly /><input id="newRule" type="hidden" /></label></div>`;const fill=(node,values,format=x=>x,keep)=>{node.innerHTML=values.map(v=>`<option value="${v}">${format(v)}</option>`).join('');if(values.includes(keep))node.value=keep};const updateRule=()=>{const match=data.rules.find(r=>r.firm===$('#newFirm').value&&r.accountType===$('#newType').value&&r.size===+$('#newSize').value);$('#newRule').value=match?.name||'';$('#newRuleDisplay').value=match?`${match.firm} — ${match.accountType} · ${fmt(match.size)}`:'No matching rules found'};const updateSizes=()=>{const rules=data.rules.filter(r=>r.firm===$('#newFirm').value&&r.accountType===$('#newType').value);fill($('#newSize'),[...new Set(rules.map(r=>r.size))],fmt,$('#newSize').value?+$('#newSize').value:undefined);updateRule()};const updateTypes=()=>{const types=[...new Set(data.rules.filter(r=>r.firm===$('#newFirm').value).map(r=>r.accountType))];fill($('#newType'),types,x=>x,$('#newType').value);updateSizes()};$('#newFirm').onchange=updateTypes;$('#newType').onchange=updateSizes;$('#newSize').onchange=updateRule;updateTypes();saveButton.onclick=e=>{e.preventDefault();const r=data.rules.find(r=>r.name===$('#newRule').value);if(!r){toast('No rule set matches this selection');return}data.accounts.push({id:$('#newAccountId').value.trim(),firm:r.firm,accountType:r.accountType,size:r.size,stage:$('#newStage').value,rule:r.name});save();d.close();renderAll();toast('Account added with matching rules')};}d.showModal()}

