function addFirmDialog(){if(!isAdmin()){toast('Only the administrator can add prop firms');return}const d=$('#formDialog');$('#dialogTitle').textContent='Add prop firm';$('#dialogFields').innerHTML='<div class="form-grid"><label class="input-label full">Prop firm name<input id="propFirmName" required placeholder="e.g. Funded Next" /></label></div>';$('#dialogSave').onclick=e=>{e.preventDefault();const name=$('#propFirmName').value.trim();if(!name)return;if(data.propFirms.some(f=>f.toLowerCase()===name.toLowerCase())){toast('This prop firm already exists');return}data.propFirms.push(name);save();d.close();renderPropFirms();toast('Prop firm added. You can now add its rule sets.')};d.showModal()}
function separateRuleDialog(){if(!isAdmin()){toast('Only the administrator can add rule sets');return}const d=$('#formDialog'),f=$('#dialogFields');const input=(label,id,type='text')=>`<label class="input-label">${label}<input id="${id}" type="${type}" required /></label>`;$('#dialogTitle').textContent='Add rule set';f.innerHTML=`<div class="form-grid"><p class="form-section">1. Prop firm</p><label class="input-label">Prop firm name<select id="separateFirm">${data.propFirms.map(x=>`<option>${x}</option>`).join('')}</select></label><span></span><p class="form-section">2. Account type</p>${input('Account type','separateType')}<span></span><p class="form-section">3. Account size</p>${input('Account size','separateSize','number')}<span></span><p class="form-section">4. Rules</p>${input('Max drawdown','separateDd','number')}<label class="input-label">Drawdown type<select id="separateDrawdown"><option>Static</option><option selected>Trailing</option></select></label>${input('Profit target','separateTarget','number')}${input('Daily loss limit','separateDaily','number')}${input('Buffer required','separateBuffer','number')}${input('Benchmark amount','separateBenchmark','number')}${input('Benchmark days','separateDays','number')}${input('Max withdrawal','separateMax','number')}</div>`;$('#dialogSave').onclick=e=>{e.preventDefault();const firm=$('#separateFirm').value,type=$('#separateType').value.trim(),size=+$('#separateSize').value;if(data.rules.some(r=>r.firm===firm&&r.accountType===type&&r.size===size)){toast('A rule set already exists for this firm, type, and size');return}data.rules.push({name:`${firm} — ${type} (${size/1000}K)`,firm,accountType:type,size,dd:+$('#separateDd').value,drawdown:$('#separateDrawdown').value,target:+$('#separateTarget').value,daily:+$('#separateDaily').value,buffer:+$('#separateBuffer').value,benchmark:+$('#separateBenchmark').value,days:+$('#separateDays').value,maxWithdrawal:+$('#separateMax').value,min:0});save();d.close();renderAll();renderPropFirms();toast('Rule set added')};d.showModal()}
