function renderDashboard(){const states=data.accounts.map(a=>({a,m:metrics(a)}));const withdrawable=states.reduce((s,x)=>s+x.m.withdrawable,0),profit=states.reduce((s,x)=>s+x.m.profit,0),atRisk=states.filter(x=>x.m.ddLeft<(x.m.rule.dd||0)*.35).length;$('#metricStrip').innerHTML=`<div class="metric"><span>Total withdrawable balance</span><strong>${fmt(withdrawable)}</strong><small>Eligible funded-account payouts</small></div><div class="metric"><span>Total open profit</span><strong>${fmt(profit)}</strong><small>From account starting balances</small></div><div class="metric warning"><span>Accounts at risk</span><strong>${atRisk}</strong><small>${atRisk?'Review before trading':'All accounts healthy'}</small></div><div class="metric"><span>Latest balance date</span><strong>${data.balances.length?dateFmt([...data.balances].sort((a,b)=>b.date.localeCompare(a.date))[0].date):'—'}</strong><small>End-of-day records</small></div>`;$('#dashboardRows').innerHTML=states.map(({a,m})=>`<tr class="open-account" data-id="${a.id}"><td><div class="account-name"><span class="initial">${a.friendlyName.slice(0,2).toUpperCase()}</span><span>${a.friendlyName}<small>${a.id}</small></span></div></td><td>${a.firm}</td><td class="money">${fmt(m.balance)}</td><td class="money ${a.stage==='Funded'&&m.bufferRemaining?'danger':'positive'}">${a.stage==='Funded'?fmt(m.bufferRemaining):fmt(Math.max(0,m.rule.target-m.profit))}</td><td class="money">${fmt(m.ddLeft)}</td><td>${a.stage==='Funded'?m.benchmarkRemaining+' days':'—'}</td><td><span class="pill ${statusClass(m.status)}">${m.status}</span></td></tr>`).join('');$$('.open-account').forEach(r=>r.onclick=()=>openAccount(r.dataset.id));const danger=[...states].sort((x,y)=>x.m.ddLeft-y.m.ddLeft);$('#riskList').innerHTML=danger.slice(0,3).map(({a,m})=>{const pct=Math.min(100,(m.ddLeft/(m.rule.dd||1))*100);return `<div class="risk-item"><div class="risk-top"><span>${a.friendlyName}</span><strong>${fmt(m.ddLeft)} left</strong></div><small>${a.firm} · ${a.id}</small><div class="progress"><span style="width:${pct}%"></span></div></div>`}).join('');renderChart()}
function structuredDialog(type){if(type!=='account')return;const d=$('#formDialog'),fields=$('#dialogFields'),saveButton=$('#dialogSave');const input=(label,id,inputType='text',extra='')=>`<label class="input-label">${label}<input id="${id}" type="${inputType}" ${extra} required /></label>`;const firms=[...new Set(data.rules.map(r=>r.firm))];$('#dialogTitle').textContent='Add account';fields.innerHTML=`<div class="form-grid">${input('Friendly account name','newFriendlyName','text','placeholder="e.g. Funded Next 50K Main"')}${input('Account ID','newAccountId')}<label class="input-label">1. Prop firm<select id="newFirm">${firms.map(f=>`<option value="${f}">${f}</option>`).join('')}</select></label><label class="input-label">2. Account type<select id="newType"></select></label><label class="input-label">3. Account size<select id="newSize"></select></label><label class="input-label">Account stage<select id="newStage"><option>Funded</option><option>Evaluation</option></select></label><label class="input-label full">4. Rules (selected automatically)<input id="newRuleDisplay" readonly /><input id="newRule" type="hidden" /></label></div>`;const fill=(node,values,format=x=>x,keep)=>{node.innerHTML=values.map(v=>`<option value="${v}">${format(v)}</option>`).join('');if(values.includes(keep))node.value=keep};const updateRule=()=>{const match=data.rules.find(r=>r.firm===$('#newFirm').value&&r.accountType===$('#newType').value&&r.size===+$('#newSize').value);$('#newRule').value=match?.name||'';$('#newRuleDisplay').value=match?`${match.firm} — ${match.accountType} · ${fmt(match.size)}`:'No matching rules found'};const updateSizes=()=>{const rules=data.rules.filter(r=>r.firm===$('#newFirm').value&&r.accountType===$('#newType').value);fill($('#newSize'),[...new Set(rules.map(r=>r.size))],fmt,$('#newSize').value?+$('#newSize').value:undefined);updateRule()};const updateTypes=()=>{const types=[...new Set(data.rules.filter(r=>r.firm===$('#newFirm').value).map(r=>r.accountType))];fill($('#newType'),types,x=>x,$('#newType').value);updateSizes()};$('#newFirm').onchange=updateTypes;$('#newType').onchange=updateSizes;$('#newSize').onchange=updateRule;updateTypes();saveButton.onclick=e=>{e.preventDefault();const r=data.rules.find(r=>r.name===$('#newRule').value);if(!r){toast('No rule set matches this selection');return}data.accounts.push({id:$('#newAccountId').value.trim(),friendlyName:$('#newFriendlyName').value.trim(),firm:r.firm,accountType:r.accountType,size:r.size,stage:$('#newStage').value,rule:r.name});save();d.close();renderAll();toast('Account added with matching rules')};d.showModal()}
