async function loadDatabaseState(){try{const response=await fetch(databaseApi);if(!response.ok)throw new Error('Database unavailable');const state=await response.json();if(state.data){data=state.data;data.rules??=[];data.accounts??=[];data.balances??=[];data.withdrawals??=[];data.rules.forEach(r=>{r.drawdown='Trailing';r.minDd??=Math.round((r.dd||0)*.25);r.buffer??=r.dd;r.days??=0;r.benchmark??=0});data.accounts.forEach(a=>{a.friendlyName??=a.id;a.accountType??=(data.rules.find(r=>r.name===a.rule)?.accountType||'Standard')});data.propFirms??=[...new Set(data.rules.map(r=>r.firm))];localStorage.setItem('proppulse-data',JSON.stringify(data));localStorage.setItem('proppulse-users',JSON.stringify(state.users||[]));renderAll();renderPropFirms()}else save()}catch{console.info('Using local backup until the PropPulse database server is available.')}}
loadDatabaseState();

function readCsv(file){if(!file)return;if(!/\.csv$/i.test(file.name)){toast('Please choose a CSV file');return}const reader=new FileReader();reader.onload=()=>{const lines=String(reader.result).replace(/^\uFEFF/,'').split(/\r?\n/).filter(line=>line.trim()!==''),header=(lines.shift()||'').trim().toLowerCase().replace(/\s/g,'');if(header!=='account_id,balance'){pending=[];renderPreview();toast('Invalid CSV header. It must be: account_id,balance');return}const seen=new Set(),formatErrors=[],records=[];lines.forEach((line,index)=>{const columns=line.split(',');const id=(columns[0]||'').trim(),balanceText=(columns[1]||'').trim(),balance=Number(balanceText),row=index+2;if(columns.length!==2)formatErrors.push(`Row ${row}: use exactly two columns`);else if(!id)formatErrors.push(`Row ${row}: account_id is missing`);else if(!Number.isFinite(balance)||balance<0)formatErrors.push(`Row ${row}: balance must be a positive number`);else if(seen.has(id))formatErrors.push(`Row ${row}: duplicate account_id ${id}`);else{seen.add(id);records.push({id,balance,account:data.accounts.find(a=>a.id===id)})}});if(!records.length||formatErrors.length){pending=[];renderPreview();toast(formatErrors[0]||'The CSV has no balance rows');return}pending=records;renderPreview();const unmatched=records.filter(r=>!r.account).length;toast(`${records.length} valid rows found${unmatched?` · ${unmatched} account ID(s) need review`:''}`)};reader.readAsText(file)}

function metrics(a){const rule=data.rules.find(r=>r.name===a.rule)||{};const entries=data.balances.filter(b=>b.id===a.id).sort((x,y)=>x.date.localeCompare(y.date));const balance=entries.at(-1)?.balance??a.size;const peak=Math.max(a.size,...entries.map(x=>x.balance));const trailingLoss=Math.max(0,peak-balance);const fundedFloorLocked=a.stage==='Funded'&&peak>=a.size+(rule.dd||0);const floor=fundedFloorLocked?a.size:peak-(rule.dd||0);const ddLeft=Math.max(0,fundedFloorLocked?balance-a.size:(rule.dd||0)-trailingLoss),profit=balance-a.size;const minDd=a.minDdWarning??rule.minDd??Math.round((rule.dd||0)*.25);const lastW=data.withdrawals.filter(w=>w.id===a.id).sort((x,y)=>y.date.localeCompare(x.date))[0];let prior=a.size;const hits=entries.reduce((n,e)=>{const pnl=e.balance-prior;prior=e.balance;return n+((!lastW||e.date>lastW.date)&&pnl>=(rule.benchmark||0)&&pnl>0?1:0)},0);const bufferRemaining=Math.max(0,(rule.buffer||0)-profit);const benchmarkRemaining=Math.max(0,(rule.days||0)-hits);const withdrawable=a.stage==='Funded'&&!(bufferRemaining>0||benchmarkRemaining>0)?Math.min(Math.max(0,profit),rule.maxWithdrawal||0):0;let status;if(a.stage==='Evaluation')status=profit>=rule.target?'Passed':ddLeft<=minDd?'Low DD':'In Progress';else status=ddLeft<=minDd?'Low DD':bufferRemaining>0?'Buffer Not Met':benchmarkRemaining>0?`Benchmark Pending (${benchmarkRemaining} Days)`:withdrawable>=(rule.maxWithdrawal||0)?'Max Reached':'Eligible';return{rule,entries,balance,peak,profit,floor,ddLeft,minDd,trailingLoss,bufferRemaining,benchmarkRemaining,withdrawable,status,hits,fundedFloorLocked};}
function editDdWarning(id){const a=data.accounts.find(x=>x.id===id),m=metrics(a),value=prompt(`Minimum DD warning for ${a.friendlyName}. Leave blank to use the rule default (${fmt(m.rule.minDd??Math.round(m.rule.dd*.25))}).`,a.minDdWarning??'');if(value===null)return;if(value.trim()==='')delete a.minDdWarning;else if(!Number.isFinite(+value)||+value<0){toast('Enter a valid positive amount');return}else a.minDdWarning=+value;save();renderAll();toast('DD warning updated')}
function renderAccounts(){$('#accountRows').innerHTML=data.accounts.map(a=>{const m=metrics(a);return `<tr><td class="money">${a.friendlyName}<small>${a.id}</small></td><td>${a.firm}</td><td>${fmt(a.size)}</td><td><span class="pill ${a.stage==='Funded'?'ok':'neutral'}">${a.stage}</span></td><td>${fmt(m.balance)}</td><td><button class="text-btn open-account-btn" data-id="${a.id}">Open →</button> <button class="text-btn dd-warning-btn" data-id="${a.id}">DD warning: ${fmt(m.minDd)}</button> <button class="text-btn delete-account" data-id="${a.id}">Remove</button></td></tr>`}).join('');$$('.open-account-btn').forEach(b=>b.onclick=()=>openAccount(b.dataset.id));$$('.dd-warning-btn').forEach(b=>b.onclick=()=>editDdWarning(b.dataset.id));$$('.delete-account').forEach(b=>b.onclick=()=>{data.accounts=data.accounts.filter(a=>a.id!==b.dataset.id);data.balances=data.balances.filter(x=>x.id!==b.dataset.id);save();renderAll();toast('Account removed')})}
function renderRules(){const admin=isAdmin();$('#newRuleBtn').classList.toggle('admin-only',!admin);$('#newFirmBtn').classList.toggle('admin-only',!admin);$('#ruleCards').innerHTML=data.rules.map((r,i)=>`<article class="panel rule-card"><div class="rule-card-head"><div><h2>${r.firm||r.name}</h2><p>${r.accountType||'Standard'} · ${fmt(r.size)} · Trailing drawdown</p></div><span class="pill ok">Trailing</span></div><div class="rule-values"><div><span>Account size</span><strong>${fmt(r.size)}</strong></div><div><span>Max drawdown</span><strong>${fmt(r.dd)}</strong></div><div><span>Min DD warning</span><strong>${fmt(r.minDd??Math.round(r.dd*.25))}</strong></div><div><span>Profit target</span><strong>${fmt(r.target)}</strong></div><div><span>Daily loss limit</span><strong>${fmt(r.daily)}</strong></div><div><span>Benchmark amount</span><strong>${fmt(r.benchmark)}</strong></div><div><span>Benchmark days</span><strong>${r.days}</strong></div><div><span>Max withdrawal</span><strong>${fmt(r.maxWithdrawal)}</strong></div></div>${admin?`<div class="rule-actions"><button class="text-btn rule-edit" data-index="${i}">Edit</button><button class="text-btn rule-delete danger" data-index="${i}">Delete</button></div>`:''}</article>`).join('');$$('.rule-edit').forEach(b=>b.onclick=()=>adminRuleEditor(+b.dataset.index));$$('.rule-delete').forEach(b=>b.onclick=()=>{if(confirm('Delete this rule set?')){data.rules.splice(+b.dataset.index,1);save();renderAll();toast('Rule set deleted')}})}
function separateRuleDialog(){if(!isAdmin()){toast('Only the administrator can add rule sets');return}const d=$('#formDialog'),f=$('#dialogFields');const input=(label,id,type='text',required=true)=>`<label class="input-label">${label}<input id="${id}" type="${type}" ${required?'required':''} /></label>`;$('#dialogTitle').textContent='Add rule set';f.innerHTML=`<div class="form-grid"><p class="form-section">1. Prop firm</p><label class="input-label">Prop firm name<select id="separateFirm">${data.propFirms.map(x=>`<option>${x}</option>`).join('')}</select></label><span></span><p class="form-section">2. Account type</p>${input('Account type','separateType')}<span></span><p class="form-section">3. Account size</p>${input('Account size','separateSize','number')}<span></span><p class="form-section">4. Rules</p>${input('Max drawdown','separateDd','number')}${input('Min DD warning','separateMinDd','number')} ${input('Profit target','separateTarget','number')}${input('Daily loss limit','separateDaily','number')}${input('Buffer required','separateBuffer','number')}${input('Benchmark amount','separateBenchmark','number')}${input('Benchmark days','separateDays','number')}${input('Max withdrawal','separateMax','number')}</div>`;$('#dialogSave').onclick=e=>{e.preventDefault();const firm=$('#separateFirm').value,type=$('#separateType').value.trim(),size=+$('#separateSize').value;if(data.rules.some(r=>r.firm===firm&&r.accountType===type&&r.size===size)){toast('A rule set already exists for this firm, type, and size');return}data.rules.push({name:`${firm} — ${type} (${size/1000}K)`,firm,accountType:type,size,dd:+$('#separateDd').value,minDd:+$('#separateMinDd').value,drawdown:'Trailing',target:+$('#separateTarget').value,daily:+$('#separateDaily').value,buffer:+$('#separateBuffer').value,benchmark:+$('#separateBenchmark').value,days:+$('#separateDays').value,maxWithdrawal:+$('#separateMax').value,min:0});save();d.close();renderAll();toast('Rule set added')};d.showModal()}
function structuredDialog(type){if(type!=='account')return;const d=$('#formDialog'),fields=$('#dialogFields'),saveButton=$('#dialogSave');const input=(label,id,inputType='text',extra='')=>`<label class="input-label">${label}<input id="${id}" type="${inputType}" ${extra} ${id==='newMinDdWarning'?'':'required'} /></label>`;const firms=[...new Set(data.rules.map(r=>r.firm))];$('#dialogTitle').textContent='Add account';fields.innerHTML=`<div class="form-grid">${input('Friendly account name','newFriendlyName','text')}${input('Account ID','newAccountId')}<label class="input-label">1. Prop firm<select id="newFirm">${firms.map(f=>`<option value="${f}">${f}</option>`).join('')}</select></label><label class="input-label">2. Account type<select id="newType"></select></label><label class="input-label">3. Account size<select id="newSize"></select></label><label class="input-label">Min DD warning (optional)<input id="newMinDdWarning" type="number" min="0" placeholder="Uses rule default" /></label><label class="input-label full">4. Rules (selected automatically)<input id="newRuleDisplay" readonly /><input id="newRule" type="hidden" /></label></div>`;const fill=(node,values,format=x=>x,keep)=>{node.innerHTML=values.map(v=>`<option value="${v}">${format(v)}</option>`).join('');if(values.includes(keep))node.value=keep};const updateRule=()=>{const match=data.rules.find(r=>r.firm===$('#newFirm').value&&r.accountType===$('#newType').value&&r.size===+$('#newSize').value);$('#newRule').value=match?.name||'';$('#newRuleDisplay').value=match?`${match.firm} — ${match.accountType} · ${fmt(match.size)} · warning ${fmt(match.minDd??Math.round(match.dd*.25))}`:'No matching rules found'};const updateSizes=()=>{const rules=data.rules.filter(r=>r.firm===$('#newFirm').value&&r.accountType===$('#newType').value);fill($('#newSize'),[...new Set(rules.map(r=>r.size))],fmt);updateRule()};const updateTypes=()=>{fill($('#newType'),[...new Set(data.rules.filter(r=>r.firm===$('#newFirm').value).map(r=>r.accountType))]);updateSizes()};$('#newFirm').onchange=updateTypes;$('#newType').onchange=updateSizes;$('#newSize').onchange=updateRule;updateTypes();saveButton.onclick=e=>{e.preventDefault();const r=data.rules.find(r=>r.name===$('#newRule').value);if(!r){toast('No rule set matches this selection');return}const warning=$('#newMinDdWarning').value;data.accounts.push({id:$('#newAccountId').value.trim(),friendlyName:$('#newFriendlyName').value.trim(),firm:r.firm,accountType:r.accountType,size:r.size,stage:'Funded',rule:r.name,...(warning!==''?{minDdWarning:+warning}:{})});save();d.close();renderAll();toast('Account added with matching rules')};d.showModal()}
function openAccountDialogWithWarning(){const d=$('#formDialog'),f=$('#dialogFields'),saveButton=$('#dialogSave'),firms=[...new Set(data.rules.map(r=>r.firm))];$('#dialogTitle').textContent='Add account';f.innerHTML=`<div class="form-grid"><label class="input-label">Friendly account name<input id="accountFriendly" required /></label><label class="input-label">Account ID<input id="accountId" required /></label><label class="input-label">Prop firm<select id="accountFirm">${firms.map(x=>`<option>${x}</option>`).join('')}</select></label><label class="input-label">Account type<select id="accountType"></select></label><label class="input-label">Account size<select id="accountSize"></select></label><label class="input-label">Account stage<select id="accountStage"><option>Funded</option><option>Evaluation</option></select></label><label class="input-label">Min DD warning (optional)<input id="accountMinDd" type="number" min="0" placeholder="Uses rule default" /></label><label class="input-label full">Rules (selected automatically)<input id="accountRuleDisplay" readonly /><input id="accountRule" type="hidden" /></label></div>`;const options=(el,items,show=x=>x)=>el.innerHTML=items.map(x=>`<option value="${x}">${show(x)}</option>`).join('');const rule=()=>{const r=data.rules.find(x=>x.firm===$('#accountFirm').value&&x.accountType===$('#accountType').value&&x.size===+$('#accountSize').value);$('#accountRule').value=r?.name||'';$('#accountRuleDisplay').value=r?`${r.firm} — ${r.accountType} · ${fmt(r.size)} · warning ${fmt(r.minDd??Math.round(r.dd*.25))}`:'No matching rules found'};const sizes=()=>{const rs=data.rules.filter(r=>r.firm===$('#accountFirm').value&&r.accountType===$('#accountType').value);options($('#accountSize'),[...new Set(rs.map(r=>r.size))],fmt);rule()};const types=()=>{options($('#accountType'),[...new Set(data.rules.filter(r=>r.firm===$('#accountFirm').value).map(r=>r.accountType))]);sizes()};$('#accountFirm').onchange=types;$('#accountType').onchange=sizes;$('#accountSize').onchange=rule;types();saveButton.onclick=e=>{e.preventDefault();const r=data.rules.find(x=>x.name===$('#accountRule').value);if(!r){toast('No rule set matches this selection');return}const warning=$('#accountMinDd').value;data.accounts.push({id:$('#accountId').value.trim(),friendlyName:$('#accountFriendly').value.trim(),firm:r.firm,accountType:r.accountType,size:r.size,stage:$('#accountStage').value,rule:r.name,...(warning!==''?{minDdWarning:+warning}:{})});save();d.close();renderAll();toast('Account added')};d.showModal()}
$('#newAccountBtn').onclick=openAccountDialogWithWarning;$('#newRuleBtn').onclick=separateRuleDialog;renderAll();

function renderAccounts(){const row=a=>{const m=metrics(a);return `<tr><td class="money">${a.friendlyName}<small>${a.id}</small></td><td>${a.firm}</td><td>${fmt(a.size)}</td><td><button class="text-btn dd-warning-btn" data-id="${a.id}">${fmt(m.minDd)}</button></td><td>${fmt(m.balance)}</td><td><span class="pill ${statusClass(m.status)}">${m.status}</span></td><td><button class="text-btn open-account-btn" data-id="${a.id}">Open →</button> <button class="text-btn delete-account" data-id="${a.id}">Remove</button></td></tr>`};const fill=(selector,accounts,label)=>$(selector).innerHTML=accounts.length?accounts.map(row).join(''):`<tr class="empty"><td colspan="7">No ${label} accounts yet.</td></tr>`;fill('#fundedAccountRows',data.accounts.filter(a=>a.stage==='Funded'),'funded');fill('#evaluationAccountRows',data.accounts.filter(a=>a.stage==='Evaluation'),'evaluation');$$('.open-account-btn').forEach(b=>b.onclick=()=>openAccount(b.dataset.id));$$('.dd-warning-btn').forEach(b=>b.onclick=()=>editDdWarning(b.dataset.id));$$('.delete-account').forEach(b=>b.onclick=()=>{data.accounts=data.accounts.filter(a=>a.id!==b.dataset.id);data.balances=data.balances.filter(x=>x.id!==b.dataset.id);save();renderAll();toast('Account removed')})}
renderAll();
